import sys

def nth_palindrome(n):
    if n == 1:
        return 0
    length = len(str(n))
    half = (length + 1) // 2
    prefix = int(str(n - 1))
    prefix_str = str(prefix)
    if len(prefix_str) < half:
        prefix_str = '0' * (half - len(prefix_str)) + prefix_str
    palindrome = prefix_str + prefix_str[-2::-1]
    return int(palindrome)

def main():
    n = int(sys.stdin.read())
    print(nth_palindrome(n))

if __name__ == "__main__":
    main()
